// Assemble the gpt-image-2 EDIT prompt for the article poster. Initial renders
// paint approved content into an immutable master; feedback renders instead edit
// the latest finished poster. Image edits regenerate the whole canvas, so keeping
// unrequested layout and Devanagari text unchanged is necessarily best-effort.
//
// The initial-render prompt is deliberately LAYOUT-AGNOSTIC: the article masters
// are a varied library (curved side panels, top bands, full-bleed photos,
// text-only), and hardcoding any one anatomy here made the image model reshape
// every master toward it — which is why all posters used to come out with the
// same curved left panel. Structure is asserted only from layout_summary /
// has_photo_zone (the picked master's vision-derived layout_spec, migration 0016,
// flattened to strings by the API); when those are empty (un-analyzed master or
// old API) the prompt stays generic and conditional.
//
// The RESERVED ZONES rule is stated FIRST, before the erase instruction, and
// repeated as a final check: the API stamps the logo/footer over those areas after
// the render, and the model used to reflow the headline UP into the top-left after
// being told to erase the master's logo there — the stamped logo then clipped the
// headline's first line. Zone numbers (top-left 420x180, bottom 150px at 1536x1024)
// must stay in sync with packages/poster-renderer/src/article-chrome.ts.
//
// Annotated feedback (marker_count > 0) edits a poster carrying numbered red
// marker boxes: apply each numbered change at its marker, then erase the marks.
const src = $input.first().json;
const headline = (src.headline || '').toString().trim();
const scene_brief = (src.scene_brief || '').toString().trim();
const reference_url = (src.reference_url || '').toString().trim();
const image_feedback = (src.image_feedback || '').toString().trim();
const panel_color = (src.panel_color || '').toString().trim();
const panel_color_name = (src.panel_color_name || '').toString().trim() || 'orange';
const headline_color = (src.headline_color || '').toString().trim() || '#7a1512';
const panel_desc = panel_color ? (panel_color_name + ' (' + panel_color + ')') : panel_color_name;
const marker_count = Math.max(0, Math.min(3, Number(src.marker_count) || 0));
const layout_summary = (src.layout_summary || '').toString().trim();
// Tri-state: true / false / null (unknown — un-analyzed master or feedback edit).
const has_photo_zone = src.has_photo_zone === 'true' ? true : (src.has_photo_zone === 'false' ? false : null);

// Fail loud rather than editing a stale canonical master: the API must send either
// the selected immutable master (initial render) or latest poster (feedback).
if (!reference_url) { throw new Error('No "reference_url" received in the webhook body — the API must send the image URL to edit.'); }

let prompt;
if (image_feedback && marker_count > 0) {
  prompt = [
    'You are editing an existing finished DGIPR Maharashtra government ARTICLE poster provided as the input image.',
    'The input image carries ' + marker_count + ' numbered red annotation marker(s): thin red outline rectangles, each with a small red circular badge showing its number. They were drawn onto the poster by editing software and are NOT part of the poster design.',
    'Each marker is a pointing gesture showing where one requested change applies — not a hard boundary. For each marker, identify the design element at or around that spot and apply the correspondingly numbered change from the request below to that WHOLE element, even where the element extends beyond the rectangle.',
    'REQUESTED CHANGES: «' + image_feedback + '».',
    'Make ONLY these changes. Keep the exact layout, the poster\'s existing panels and accent shapes, existing Marathi headline text, colours, typography, and any photograph unchanged except where a requested change explicitly requires it.',
    'ERASE every red marker rectangle and numbered badge completely from the output, restoring whatever they overlapped — no red outlines, red circles, or annotation numbers may remain anywhere on the poster.',
    'RESERVED ZONES: the महासंवाद logo in the top-left (approx 420x180 px) and the footer strip along the bottom (full width, approx 150 px tall) are official branding stamped onto the poster by software — do NOT alter, move, redraw or remove them, and do NOT move any text or important content into those areas.',
    'Add no new text, letters, numbers, captions, logos, borders, or decorative elements beyond the requested changes. Preserve all other existing Devanagari text exactly. Output ONE complete landscape poster filling the canvas.',
  ].join('\n');
} else if (image_feedback) {
  prompt = [
    'You are editing an existing finished DGIPR Maharashtra government ARTICLE poster provided as the input image.',
    'Apply ONLY this requested change: «' + image_feedback + '».',
    'Keep the exact layout, the poster\'s existing panels and accent shapes, existing Marathi headline text, colours, typography, and any photograph unchanged except where the requested change explicitly requires it.',
    'RESERVED ZONES: the महासंवाद logo in the top-left (approx 420x180 px) and the footer strip along the bottom (full width, approx 150 px tall) are official branding stamped onto the poster by software — do NOT alter, move, redraw or remove them, and do NOT move any text or important content into those areas.',
    'Add no new text, letters, numbers, captions, logos, borders, or decorative elements. Preserve all existing Devanagari text exactly. Output ONE complete landscape poster filling the canvas.',
  ].join('\n');
} else {
  if (!headline) { throw new Error('No "headline" received in the webhook body.'); }

  // The PHOTO instruction branches on what the master actually contains:
  // replace-in-place when it provably has a photo zone, a hard no-imagery lock
  // when it provably has none, and a conditional clause when un-analyzed.
  let photoLines;
  if (has_photo_zone === true) {
    photoLines = [
      '3) PHOTO — this master has a photo zone. Erase the photograph currently inside it and fill that SAME zone — same shape, same position, same edges — with a NEW realistic documentary photograph matching the description below. Do not move, resize or reshape the zone. The photo must contain NO text, words, letters, numbers or logos.',
      'PHOTO (imagery only): ' + (scene_brief || 'a relevant Maharashtra public-welfare documentary scene'),
    ];
  } else if (has_photo_zone === false) {
    photoLines = [
      '3) NO PHOTOGRAPHY — this master is a text-and-graphics layout with NO photo zone. Do NOT add any photograph, portrait, illustration or pictorial scene anywhere on the poster; keep the master\'s text-and-graphics structure exactly.',
    ];
  } else {
    photoLines = [
      '3) PHOTO — only IF this master devotes a region to a photograph: erase that photograph and fill the SAME region — same shape, same position — with a NEW realistic documentary photograph matching the description below; the photo must contain NO text, words, letters, numbers or logos. IF the master has NO photo region, do NOT add one.',
      'PHOTO (imagery only): ' + (scene_brief || 'a relevant Maharashtra public-welfare documentary scene'),
    ];
  }

  prompt = [
    'You are editing an OFFICIAL DGIPR Maharashtra government ARTICLE poster: a single landscape banner on a 1536x1024 canvas.',
    'RESERVED ZONES — READ THIS FIRST. Two rectangles of this canvas are already spoken for: the official logo and footer graphics are stamped onto the finished poster afterwards by software, laid OVER whatever you paint there. (a) The TOP-LEFT rectangle from (0,0) to (420,180) — the leftmost ~27% of the width across the topmost ~18% of the height. (b) The FULL-WIDTH BOTTOM strip, approx 150 px tall. These two rectangles must contain NOTHING: no headline, no text, no letters, no numbers, no statistics, no faces, no photograph, no logo, no decorative element, no important visual subject matter. Plain flat colour or quiet background continuation there is expected and correct. Compose the poster the way a human designer would who knows the logo and footer will cover those areas and must not hide any information.',
    '',
    'KEEP THIS master template\'s layout EXACTLY as provided — the same composition, panel shapes, colour zones, decorative elements and arrangement THIS particular master has. Do NOT restructure it toward any other poster layout, do NOT add panels or shapes it does not have, and do NOT remove ones it does have.',
    ...(layout_summary ? ['THIS master\'s structure, read from the template itself: ' + layout_summary] : []),
    'ERASE the branding chrome the master carries: any महासंवाद logo card in the top-left and any department footer band or social-handle strip along the bottom. Fill those areas by continuing the surrounding panel colour, photograph or background naturally, as if that branding was never there. Erasing that branding does NOT free up space — those areas remain RESERVED ZONES as defined above. Do NOT move, enlarge, re-centre or reflow the headline, the photograph, or any other element into the space the erased branding occupied; leave it as quiet empty background.',
    '',
    'REPLACE the master\'s placeholder content, inside the master\'s OWN existing zones:',
    '',
    '1) HEADLINE — erase the master\'s existing main Marathi headline, wherever this master places it, and typeset THIS headline in that same zone, matching the master\'s headline placement, scale, alignment and weight, spelled EXACTLY as given, in correct Devanagari (Marathi). Large, bold and crisply legible. The FIRST line of the headline must START BELOW approx 190 px from the top of the canvas, entirely clear of the reserved top-left zone, and must not extend into the bottom strip; if the headline is long, reduce its type size or extend the block DOWNWARD — never upward or leftward into the reserved top-left zone. Also erase any OTHER placeholder Marathi wording the master carries (sub-lines, year badges, old scheme names) — stale placeholder text must not survive. The new headline is the ONLY text you add anywhere on the poster.',
    'HEADLINE (verbatim, do not translate or alter): ' + headline,
    '',
    '2) COLOUR — IF this master has a distinct solid-colour headline panel or band, recolour that panel to ' + panel_desc + ' as a solid flat fill, keeping the panel\'s exact shape, size and position; if the master has no such panel, keep the master\'s own colour scheme unchanged. Set the headline text in ' + headline_color + ' if that stays crisply legible against its background; otherwise use the colour the master\'s own headline used.',
    '',
    ...photoLines,
    '',
    'Add NO other text: no subhead, no bullet points, no statistics, no quotes, no logos of any kind, no captions, and no outer border. Output ONE complete poster filling the whole canvas.',
    'FINAL CHECK before you output: the top-left 420x180 rectangle and the full-width bottom 150 px strip must be empty quiet background — no part of the headline, no photograph, no subject matter and no branding anywhere inside them.',
  ].join('\n');
}

return [{ json: { prompt, headline, scene_brief, reference_url, image_feedback, generation_id: src.generation_id } }];
